#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define MAXN 100005
#define MAXM 300005
typedef struct { int to, w, next; } Edge;
Edge edges[MAXM];
int head[MAXN], edge_cnt = 0;
long long dist[MAXN];
int src[MAXN];
void add_edge(int u, int v, int w) { edges[edge_cnt].to = v; edges[edge_cnt].w = w; edges[edge_cnt].next = head[u]; head[u] = edge_cnt++; }
void dijkstra(int src) {
    long long d[MAXN];
    for (int i = 1; i <= N; i++) d[i] = LLONG_MAX;
    d[src] = 0;
    long long ans = LLONG_MAX;
    for (int i = 1; i <= N; i++) {
        for (int e = head[i]; e != -1; e = edges[e].next) {
            int v = edges[e].to;
            long long nd = d[i] + edges[e].w;
            if (nd < d[v]) {
                d[v] = nd;
                if (src[v] != src[i]) ans = min(ans, d[v] + nd);
            }
        }
    }
    printf("%lld\n", ans);
}
int main() {
    int N, M, K;
    scanf("%d %d %d", &N, &M, &K);
    for (int i = 1; i <= N; i++) head[i] = -1;
