import java.io.*;
import java.util.*;
public class Main {
    static final int N = 100005;
    static final int M = 300005;
    static class Pair {
        int node;
        long wt;
        Pair(int n, long w) {
            node = n;
            wt = w;
        }
    }
    static class State {
        long cost;
        int node;
        State(long c, int n) {
            cost = c;
            node = n;
        }
    }
    static ArrayList<Pair>[] graph = new ArrayList[N];
    static long[] dist = new long[N];
    static int[] src = new int[N];
    static void dijkstra(int src) {
        PriorityQueue<State> pq = new PriorityQueue<>((a, b) -> Long.compare(a.cost, b.cost));
        for (int i = 1; i <= N; i++) dist[i] = Long.MAX_VALUE;
        dist[src] = 0;
        pq.add(new State(0, src));
        long ans = Long.MAX_VALUE;
        while (!pq.isEmpty()) {
            State cur = pq.poll();
            long d = cur.cost;
            int u = cur.node;
            if (d != dist[u]) continue;
            for (Pair edge : graph[u]) {
                long nd = d + edge.wt;
                if (nd < dist[edge.node]) {
                    dist[edge.node] = nd;
                    if (src[edge.node] != src[u]) ans = Math.min(ans, dist[edge.node] + nd);
                    pq.add(new State(nd, edge.node));
                }
            }
        }
        System.out.println(ans);
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int N = Integer.parseInt(st.nextToken());
        int M = Integer.parseInt(st.nextToken());
        int K = Integer.parseInt(st.nextToken());
        for (int i = 0; i < N; i++) graph[i] = new ArrayList<>();
        for (int i = 0; i < K; i++) {
            int x = Integer.parseInt(br.readLine());
            src[x] = x;
        }
        for (int i = 0; i < M; i++) {
            st = new StringTokenizer(br.readLine());
            int x = Integer.parseInt(st.nextToken());
            int y = Integer.parseInt(st.nextToken());
            long z = Long.parseLong(st.nextToken());
            graph[x].add(new Pair(y, z));
            graph[y].add(new Pair(x, z));
        }
        for (int i = 1; i <= N; i++) if (src[i] != 0) dijkstra(i);
    }
}

